"""
MKT Original Commentary — Hebrews chapters 10–11 (gap-fill pass)
Run: python3 scripts/zc-original-hebrews-10-11-gaps.py

Source data used:
- data/interlinear/hebrews.json
- data/translation/draft/mediating/hebrews.json (MKT text)

Key decisions in this range:
- 10:3 anamnesis: active memorial of sins; contrast with 8:12 ou mē mnēsthō eti
- 10:12 eis to diēnekes: in perpetuity (mathematical/administrative term for continuous running total)
- 10:20 prosphaton: freshly-killed/new; curtain identified with Christ's flesh
- 10:29 three escalating participles: trampling → profaning → insulting the Son
- 10:37 ho erchomenos: LXX Hab 2:3 reads a person (the Coming One) not a vision as MT
- 11:17 prosenenoken (perfect)/prosepheren (imperfect): offered (completed in God's sight) + was offering (process underway)
- 11:19 en parabolē: in a parable/type; Isaac's survival as prefiguring resurrection
- 11:40 kreition ti problepsamenos: God's foresight arranges the corporate completion of OT and NT saints
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = json.loads(r"""
{
  "10": {
    "2": "<p><strong>epei ouk an epausanto prospheromenai, dia to mēdemian echein eti syneidēsin hamartiōn tous latreuontas hapax kekathrismenous</strong> — \"for if they could have, would they not have stopped being offered? Because the worshippers, once truly cleansed, would no longer have been conscious of their sins\" (<em>syneidēsin hamartiōn</em>: consciousness/conscience of sins — <em>syneidēsis</em>: the inner moral awareness, the shared-knowing of the self with itself; the consciousness of sin is the awareness that the guilt-problem remains unresolved): the argument is from silence converted to speech: the continued repetition of sacrifices is itself evidence of their incompleteness — if they had truly resolved sin, there would be nothing left to repeat. <em>Hapax kekathrismenous</em> (having been cleansed once): the <em>hapax</em> here is the goal never achieved under the old system but achieved by Christ.</p>",
    "3": "<p><strong>all' en autais anamnēsis hamartiōn kat' eniauton</strong> — \"instead, in those sacrifices there is an annual reminder of sins\" (<em>anamnēsis hamartiōn</em>: a remembrance/memorial of sins — <em>anamnēsis</em>: active recalling, not passive memory; the word used in the eucharistic tradition [Luke 22:19; 1 Cor 11:24-25] for the remembrance-unto-presence that the Lord's Supper effects): the annual sacrifice functions as an <em>anamnēsis</em> of sins — a formal re-membering that the sin problem persists, an annual re-presentation of the guilt before God. Contrast with 8:12: the new covenant promise is that sins will be <em>remembered no more</em> (<em>ou mē mnēsthō eti</em>).</p>",
    "6": "<p><strong>holokautōmata kai peri hamartias ouk eudokēsas</strong> — \"in burnt offerings and offerings for sin you took no pleasure\" (Ps 40:6 LXX, continued): <em>ouk eudokēsas</em> (you did not take pleasure — aorist: a completed act of divine non-pleasure): the divine dissatisfaction is not with the obedience that offered these sacrifices but with the inadequacy of animal sacrifice as a vehicle for the relational-moral restoration God desires. The Psalm reads God's heart as desiring obedience over sacrifice (cf. Mic 6:6-8; Hos 6:6) — a prophetic tradition that Hebrews enlists to show the Levitical system was always interim.</p>",
    "7": "<p><strong>tote eipon, Idou hēkō, en kephalidi bibliou gegraptai peri emou, tou poiēsai, ho theos, to thelēma sou</strong> — \"then I said, See, I have come to do your will, O God, as it is written about me in the scroll of the book\" (Ps 40:7-8 LXX): <em>en kephalidi bibliou</em> (in the head/roll of the book — <em>kephalis</em>: scroll-roller, the end of the scroll where the title was; or the beginning/heading of the scroll): the Son identifies himself as the one about whom the entire scriptural scroll is written — not merely a verse here or there but the whole. <em>Tou poiēsai... to thelēma sou</em> (to do your will): the Son's incarnation is defined as will-doing — he comes not to perform animal sacrifices but to perform the will of God that the sacrifices symbolized.</p>",
    "8": "<p><strong>anoteron legōn hoti Thysias kai prosphoras kai holokautōmata kai peri hamartias ouk ēthelēsas oude eudokēsas, haitines kata nomon prospherontai</strong> — \"when he said above, You have not desired nor taken pleasure in sacrifices and offerings and burnt offerings and sin offerings — which are offered in accordance with the law\" (<em>kata nomon prospherontai</em>: offered according to the law — the parenthetical clarification that these are the very offerings the Torah prescribes): the argument is careful: God commanded the Levitical system through Moses, yet through the Psalms God also says he does not desire those same offerings. The resolution is that the commandments governed the pedagogical interim; the Psalm reveals the heart that the system was always pointing toward.</p>",
    "9": "<p><strong>tote eirēken, Idou hēkō tou poiēsai to thelēma sou; anairei to prōton hina to deuteron stēsē</strong> — \"then he added, Behold, I have come to do your will. He removes the first covenant order in order to establish the second\" (<em>anairei to prōton</em>: he removes/takes away the first — <em>anairei</em>: present tense, actively removing): <em>anairō</em> has the sense of lifting up and taking away — the same word used for executing/removing someone (Acts 2:23, 5:33). The removal of the first is the act that creates space for the second. <em>Hina to deuteron stēsē</em> (so that he might establish the second — aorist subjunctive: a completed, decisive establishment): the two covenants cannot coexist permanently; the establishment of the second requires the removal of the first.</p>",
    "12": "<p><strong>houtos de mian hyper hamartiōn prospheras thysian eis to diēnekes ekathisen en dexia tou theou</strong> — \"but this priest, having offered one sacrifice for sins for all time, sat down at the right hand of God\" (<em>mian thysian</em>: one sacrifice — the numerical contrast with the many; <em>eis to diēnekes</em>: in perpetuity, continuously, for all time — <em>diēnekes</em>: carried through without break, uninterrupted; a mathematical/administrative term for a continuous running total): <em>ekathisen</em>: sat down — the single aorist that the entire argument builds toward. The sitting is the posture of completed work; no chair in the sanctuary because no Levitical work was ever complete. The seated Son marks the ending of a priestly service that is not repeated.</p>",
    "13": "<p><strong>to loipon ekdechomenos heōs tethōsin hoi echthroi autou hypopodion tōn podōn autou</strong> — \"waiting from that time until his enemies are made a footstool for his feet\" (<em>ekdechomenos</em>: waiting, expecting — present active participle: the Son's current activity is expectant waiting): the posture pairs sitting (completed sacrifice) with waiting (expected consummation). The session is not passive inactivity but active intercession (7:25) combined with sovereign expectancy. <em>Hypopodion tōn podōn autou</em> (footstool for his feet — Ps 110:1): the language of absolute dominion; the footstool-enemy is the one fully subdued under the victor's feet in ancient Near Eastern victory imagery.</p>",
    "14": "<p><strong>mia gar prosphora teteleiōken eis to diēnekes tous hagiazomenous</strong> — \"for by a single offering he has brought to completion for all time those who are being made holy\" (<em>teteleiōken</em>: he has brought to completion, perfected — perfect active: the perfecting stands as a completed act with ongoing results): <em>tous hagiazomenous</em>: those being sanctified — present passive participle: the community's sanctification is an ongoing process, but it rests on the completed perfecting act of the one offering. The perfect <em>teteleiōken</em> + present <em>hagiazomenous</em> holds together the finished work and the ongoing application.</p>",
    "15": "<p><strong>martyrei de hēmin kai to pneuma to hagion</strong> — \"the Holy Spirit also bears witness to us concerning this\" (<em>martyrei</em>: bears witness, testifies — present tense: the Spirit continues to testify through Scripture): the testimony is ongoing — not merely a past utterance but a present testimony that reaches the community through its reading of the OT. The Spirit who spoke through Jeremiah continues to speak the same word. <em>Hēmin</em> (to us): the first-person plural signals that the scriptural testimony is not merely historical but addressed to the present community.</p>",
    "16": "<p><strong>hautē hē diathēkē hēn diathēsomai pros autous meta tas hēmeras ekeinaslegeicurios: didonai nomous mou epi kardias autōn, kai epi tēs dianoias autōn epigrapsō autous</strong> — \"This is the covenant I will make with them after those days, says the Lord: I will put my laws on their hearts and write them on their minds\" (Jer 31:33, repeated from 8:10): the repetition of the Jer 31 citation is not redundant but deliberate — it frames the argument about Christ's one sacrifice with the promise of the new covenant's complete internalized forgiveness. <em>Epi kardias... epi tēs dianoias</em> (on hearts... on minds): heart and mind together represent the whole inner person; the law is inscribed on both the affective and cognitive dimensions.</p>",
    "17": "<p><strong>kai tōn hamartiōn autōn kai tōn anomiōn autōn ou mē mnēsthō eti</strong> — \"I will remember their sins and their lawless deeds no more\" (Jer 31:34 LXX, final clause): <em>ou mē mnēsthō eti</em>: the emphatic double-negative + aorist subjunctive + <em>eti</em> (still/any longer) — the absolute divine non-recollection. The citation concludes the long scriptural argument: the new covenant achieves what the Levitical system could not — the permanent resolution of the sin-problem through God's deliberate covenant-forgetting. The citation is placed after the description of Christ's completed sacrifice to show: the sacrifice achieves what the Jeremiah promise required.</p>",
    "18": "<p><strong>hopou de aphesis toutōn, ouketi prosphora peri hamartias</strong> — \"where there is forgiveness of these sins, there is no longer any offering for sin\" (<em>aphesis</em>: forgiveness, release — the letting-go of the debt/obligation): the logical conclusion drawn from the Jer 31 citation: if sins are no longer remembered by God, no mechanism remains for addressing them. <em>Ouketi prosphora peri hamartias</em>: no longer an offering for sin — the sacrificial system becomes structurally unnecessary once its goal has been achieved. This verse is the pivot from the doctrinal argument (chs 7-10:18) to the parenetic application (10:19-39).</p>",
    "20": "<p><strong>hēn enekainisen hēmin hodon prosphaton kai zōsan dia tou katapetasmatos, tout' estin tēs sarkos autou</strong> — \"by the new and living way that he opened for us through the curtain, that is, through his flesh\" (<em>prosphaton</em>: freshly slaughtered, new — from <em>pros</em> + <em>sphattō</em>: the freshly-killed; <em>prosphatos</em> could mean both newly-made and freshly-sacrificed, which is significant for the sacrificial context): <em>zōsan</em> (living): the way is living because the one who opened it is alive; the death through which access was gained was not the end of the story. <em>Tou katapetasmatos, tout' estin tēs sarkos autou</em> (the curtain, that is, his flesh): the identification of the curtain with Christ's flesh is the interpretive move — the curtain in the tabernacle separated the holy from the most holy; Christ's body was the barrier between humanity and God's presence that his death opened.</p>",
    "21": "<p><strong>kai hierea megan epi ton oikon tou theou</strong> — \"and since we have a great high priest over the house of God\" (<em>hierea megan</em>: a great priest — the superlative epithet echoing 4:14; <em>epi ton oikon tou theou</em>: over the house of God): the \"house of God\" picks up the <em>oikos</em>-language of ch3 (Moses faithful in the house; Christ faithful over the house). The community is both the house and the assembled worshippers who now have access to what the house symbolized.</p>",
    "22": "<p><strong>proserchōmetha meta alēthinēs kardias en plērophoria pisteōs, errantismenoi tas kardias apo syneidēseōs ponēras kai leloumenoi to sōma hydati katharō</strong> — \"let us draw near with a sincere heart and in full assurance of faith, with our hearts sprinkled clean from an evil conscience and our bodies washed with pure water\" (<em>proserchōmetha</em>: let us draw near — hortatory subjunctive echoing 4:16; the same verb for priestly approach to the sanctuary): <em>errantismenoi tas kardias</em> (hearts having been sprinkled — perfect passive participle: the sprinkling has already occurred and its state remains): the language maps Old Covenant purification rites onto the inner person: the heart is the locus of the sprinkling. <em>Leloumenoi to sōma hydati katharō</em> (bodies washed with pure water — also perfect passive): the two perfects (sprinkled hearts, washed bodies) describe the completed state that enables the drawing-near.</p>",
    "24": "<p><strong>kai katanōomen allēlous eis paroxysmon agapēs kai kalōn ergōn</strong> — \"and let us consider how to spur one another on to love and good works\" (<em>katanōomen</em>: let us observe carefully, consider attentively — same verb as 3:1 [consider Jesus]; the verb requires fixing attention on something with intention): <em>paroxysmon</em>: provocation, stimulation, incitement — the noun is from <em>paroxynō</em>: to sharpen to a point, to provoke; the cognate gave us \"paroxysm\" in English. The provocative stimulation is positive here — goading one another toward love, not toward dispute (Acts 15:39 uses the same word for Paul and Barnabas's sharp disagreement). <em>Agapēs kai kalōn ergōn</em> (love and good works): the two outcomes that the mutual provocation is to produce.</p>",
    "27": "<p><strong>phobera de tis ekdochē kriseōs kai pyrōs zēlos esthiein mellontos tous hypenantious</strong> — \"but a terrifying expectation of judgment and a raging fire that will consume the adversaries of God\" (<em>ekdochē</em>: expectation, receiving — waiting to receive something; the word implies the thing awaited is already determined and approaching): <em>pyrōs zēlos</em>: a jealousy/fury of fire — <em>zēlos</em> can mean either jealousy (jealous fire) or zealousness (fierce fire); the genitive describes the fire's quality as consuming-zeal. <em>Tous hypenantious</em>: the adversaries, those who stand against — those who reject the Son become adversaries of God.</p>",
    "28": "<p><strong>athetēsas tis nomon Mōyseōs chōris oiktirmōn epi dysin ē trisin martyrsin apothnēskei</strong> — \"anyone who rejected the law of Moses died without mercy on the evidence of two or three witnesses\" (<em>athetēsas</em>: aorist participle of <em>atheteō</em>: to set aside as if nonexistent, to nullify — the same word used in 7:18 for the setting-aside of the commandment): the conditional-analogical structure: if the lesser (Mosaic law-rejection) carried capital punishment without mercy, how much more the greater? <em>Chōris oiktirmōn</em>: without compassions — <em>oiktirmos</em>: the gut-feeling of compassion, the visceral mercy; the court could not allow emotion to override the Deuteronomic death-penalty requirement (Deut 17:6).</p>",
    "29": "<p><strong>posō dokite cheironos axióthēsetai timōrias ho ton huion tou theou katapatēsas, kai to haima tēs diathēkēs koinon hēgēsamenos, en hō hēgiasthē, kai to pneuma tēs charitos enybrisas</strong> — \"how much worse punishment, do you think, will be deserved by the one who has trampled underfoot the Son of God, has treated as something common the blood of the covenant by which he was sanctified, and has insulted the Spirit of grace\" (<em>katapatēsas</em>: having trampled underfoot — the image of complete contempt, treating what is most holy as street-dirt): <em>koinon hēgēsamenos</em> (having considered common/profane — <em>koinos</em>: what belongs to everyone, thus defiled, unclean): the covenant blood is considered no better than ordinary blood. <em>Enybrisas</em>: having insulted, outraged — <em>hybrizō</em>: to treat with contempt that demeans; the three aorist participles escalate in severity: trampling → profaning → insulting.</p>",
    "30": "<p><strong>oidamen gar ton eiponta, Emoi ekdikēsis, egō antapodōsō; kai palin, Krinei kyrios ton laon autou</strong> — \"for we know him who said, Vengeance is mine; I will repay, and again, The Lord will judge his people\" (Deut 32:35-36 cited): <em>Emoi ekdikēsis</em> (Vengeance belongs to me — the divine possessive): the citation from the Song of Moses establishes the divine monopoly on recompense. <em>Krinei Kyrios ton laon autou</em>: the Lord judges his people — the judgment is not of outsiders but of the covenant people. The second citation (Deut 32:36) is a warning that the covenant relationship does not insulate from divine judgment but rather intensifies accountability.</p>",
    "32": "<p><strong>anamimNēskesthe de tas proteron hēmeras, en hais phōtisthentes pollēn athlēsin hypemeinete pathēmatōn</strong> — \"but recall the earlier days when, after you were enlightened, you endured a hard and painful struggle\" (<em>anami mnēskesthe</em>: recall, bring back to memory — present imperative: ongoing recollection as a pastoral resource): <em>phōtisthentes</em> (having been enlightened — aorist passive: the completed event of baptism/conversion; the same word as 6:4): the community's conversion is the reference point. <em>Athlēsin</em>: an athletic contest, a struggle — <em>athleō</em>: to compete athletically; the metaphor frames the community's persecution-experience as a contest requiring both skill and endurance.</p>",
    "33": "<p><strong>touto men oneidismois te kai thlipsesin theatrizomenoi, touto de koinōnoi tōn houtōs anastrophentōn genēthentes</strong> — \"sometimes being publicly exposed to reproach and affliction, and sometimes standing alongside those who were treated this way\" (<em>theatrizomenoi</em>: being made a spectacle in the theater — <em>theatron</em>: theater, public display; the passive: being put on display for the public's entertainment): the Roman practice of public shaming and spectacle-punishment is the background. <em>Koinōnoi</em>: sharers, partners — the community's solidarity with those suffering was itself an act of faith that incurred risk; identifying with the condemned made one a target.</p>",
    "34": "<p><strong>kai gar tois desmiois synepathēsate kai tēn harpagēn tōn hyparchontōn hymōn meta charas prosedexasthe</strong> — \"for you showed compassion to those in prison and joyfully accepted the plundering of your property\" (<em>tois desmiois synepathēsate</em>: you suffered-with the prisoners — <em>synpatheō</em>: shared-suffering, co-suffering; the same root as 4:15 [the Son sympathizes with weaknesses]): <em>harpagēn</em>: plundering, seizure — the goods were forcibly taken, not voluntarily surrendered; the community's joy was not in the loss itself but in the enduring possession. <em>Ginōskontes echein heautous kreittōna hyparxin kai menousan</em> (knowing that you yourselves have a better, abiding possession): the consciousness of the better possession transforms the attitude toward the lost one.</p>",
    "35": "<p><strong>mē apobalēte oun tēn parrēsian hymōn, hētis echei megalēn misthapodosian</strong> — \"therefore do not throw away your confidence, which carries a great reward\" (<em>apobalēte</em>: aorist subjunctive of <em>apoballō</em>: to throw away, to cast off — a single decisive act of discarding): the parrēsia that was given at conversion and maintained through persecution must not be voluntarily discarded at the end. <em>Misthapodosian</em>: recompense, reward — the same word as 2:2 (the law's just <em>misthapodosia</em>); now the positive reward of faithful perseverance rather than the penalty of transgression. The parrēsia is worth keeping because what it carries is of greater value than what one might gain by abandoning it.</p>",
    "36": "<p><strong>hypomonēs gar echete chreian, hina to thelēma tou theou poiēsantes komizēsthe tēn epangelian</strong> — \"for you need endurance, so that when you have done the will of God you may receive what was promised\" (<em>hypomonēs</em>: endurance, the staying-power under pressure — <em>hypo</em>: under + <em>menō</em>: to remain; the virtue of remaining in place under the weight): <em>komizēsthe</em>: may receive, carry off — <em>komizō</em>: originally to care for and carry; the middle voice suggests personal reception of something belonging to oneself. The endurance must first produce the will-doing, which then receives the promise.</p>",
    "37": "<p><strong>eti gar mikron hoson hoson, ho erchomenos hēxei kai ou chronizei</strong> — \"for yet a little while, and the coming one will come and will not delay\" (Isa 26:20 + Hab 2:3 combined in LXX): <em>mikron hoson hoson</em>: a very little while — the double <em>hoson</em> intensifies the brevity; a Hebraism for \"just a tiny moment\"; <em>ho erchomenos</em>: the coming one — the Habakkuk text in the LXX has a person (\"he will come\") rather than the MT's \"it\" (the vision); Hebrews follows the LXX and applies the \"coming one\" to Christ. <em>Ou chronizei</em>: will not delay — <em>chronizō</em>: to linger in time, to be late; the coming is certain and near.</p>",
    "39": "<p><strong>hēmeis de ouk esmen hypostolēs eis apōleian, alla pisteōs eis peripoiēsin psychēs</strong> — \"but we do not belong to those who shrink back and are destroyed, but to those who have faith and so preserve their souls\" (<em>hypostolēs</em>: shrinking back — genitive; from <em>hypostellō</em>: to take in the sails, to shorten, to draw back; the nautical image of a ship shortening its sails in fear): <em>eis apōleian</em>: unto destruction/loss — the final state of the shrinking-back; <em>pisteōs eis peripoiēsin psychēs</em> (faith unto the preservation/acquisition of the soul — <em>peripoiēsis</em>: the acquiring for oneself, the preservation; from <em>peri</em> + <em>poieō</em>: to make-around, to secure). The community's self-definition is constituted by belonging to the faith-group, not the shrinking-back group."
  },
  "11": {
    "2": "<p><strong>en tautē gar emarturēthēsan hoi presbyteroi</strong> — \"for by this the people of old received their commendation\" (<em>emarturēthēsan</em>: were borne witness to, testified about — aorist passive: God's testimony about them came from without, not from their own self-assessment): <em>hoi presbyteroi</em>: the elders, the ancestors — not ecclesiastical officers but the patriarchs and figures of Israel's past. <em>En tautē</em> (by this faith): the antecedent is the definition of faith in v1; the OT saints were commended precisely through this faith-as-substance-and-evidence. Scripture's testimony about them constitutes the divine commendation.</p>",
    "4": "<p><strong>Pistei pleiona thysian Abel para Kain prosēnenken tō theō, di' hēs emarturēthē einai dikaios, martyrountos epi tois dōrois autou tou theou, kai di' autēs apothanōn eti lalei</strong> — \"by faith Abel brought God a better offering than Cain. Through his faith he was commended as righteous, when God himself testified about his gifts. And by his faith Abel still speaks, even though he is dead\" (<em>pleiona thysian</em>: a better/more/greater sacrifice — <em>pleionos</em>: the comparative of greatness, not specifying in what way): the text of Genesis does not explain why Abel's sacrifice was accepted; Hebrews supplies the answer: faith. <em>Eti lalei</em>: still speaks — present tense: Abel's voice continues through Scripture. The blood of Abel cried out from the ground (Gen 4:10); the author of Hebrews reads that continuing cry as the ongoing testimony of faith.</p>",
    "5": "<p><strong>Pistei Enōch metetethe tou mē idein thanaton, kai ouch heurisketo dioti metethēken auton ho theos</strong> — \"by faith Enoch was taken from this life so that he did not experience death. He could not be found, because God had taken him away\" (Gen 5:24): <em>metetethe</em>: was translated/transferred — aorist passive of <em>metatithēmi</em>: to transfer from one place to another; the same verb used for the transferring of the priesthood in 7:12. <em>Tou mē idein thanaton</em> (so as not to see death — genitive articular infinitive of result): the translation bypassed death entirely — a unique testimony to faith that pleased God. <em>Pro gar tēs metathēseōs emarturēto euaresthēkenai tō theō</em> (for before the translation he had been testified to as having pleased God — perfect infinitive: the pleasure stood as an established fact before the event).</p>",
    "7": "<p><strong>Pistei Nōe chrēmatistheis peri tōn mēdepō blepomenōn eulabētheis kateskeuasen kibōton eis sōtērian tou oikou autou, di' hēs katekrineken ton kosmon kai tēs kata pistin dikaiosynēs egeneto klēronōmos</strong> — \"by faith Noah, when warned about things not yet seen, in holy fear built an ark to save his family. By his faith he condemned the world and became heir of the righteousness that is in keeping with faith\" (<em>chrēmatistheis</em>: having been divinely warned/instructed by oracle — <em>chrēmatizō</em>: to conduct business, to receive a divine response; same verb as 8:5 [Moses instructed]): <em>eulabētheis</em>: moved with godly fear, reverently careful — <em>eulabeia</em>: the reverent-cautious posture of one who takes seriously the divine warning. <em>Katekrineken ton kosmon</em>: condemned the world — not by pronouncing judgment but by his actions: his building of the ark implicitly condemned those who did not build, as his salvation made their non-response inexcusable.</p>",
    "8": "<p><strong>Pistei kaloumenos Abraam hypēkousen exelthein eis topon hon ēmellen lambanein eis klēronomian, kai exēlthen mē epistamenos pou erchetai</strong> — \"by faith Abraham obeyed when he was called to go to a place he would later receive as his inheritance; and he set out without knowing where he was going\" (<em>hypēkousen</em>: obeyed — the root of <em>hypakoē</em> [obedience]: literally hearing-under, submissive hearing that issues in action): the grammar is precise: <em>kaloumenos</em> (present passive participle: while being called) + <em>hypēkousen</em> (aorist: he obeyed) + <em>exēlthen</em> (aorist: he went out) — the obedience and departure were simultaneous with the calling, not subsequent to deliberation. <em>Mē epistamenos pou erchetai</em>: not knowing where he was going — the faith-obedience precedes the understanding of destination.</p>",
    "9": "<p><strong>Pistei paroikēsen eis gēn tēs epangelias hōs allotrian, en skēnais katoikēsas meta Isaak kai Iakōb tōn synklēronōmōn tēs epangelias tēs autēs</strong> — \"by faith he made his home in the promised land like a stranger in a foreign country; he lived in tents, as did Isaac and Jacob, who were heirs with him of the same promise\" (<em>paroikēsen</em>: sojourned — the word for the resident-alien who lives in a land without citizenship; <em>paroikos</em> was the technical status for a foreign resident): <em>hōs allotrian</em> (as though it were foreign): the promised land is possessed through faith-promise, not by legal title — the very land promised is inhabited as though it belonged to others. <em>En skēnais katoikēsas</em>: having dwelt in tents — the tent-dwelling is a sign of the non-possessive mode of the promise: the heir lives as a guest in his own inheritance until the promise is fulfilled.</p>",
    "11": "<p><strong>Pistei kai autē Sarra steira dynamin eis katabolēn spermatos elaben kai para kairon hēlikias, epei piston hēgēsato ton epangeilamenos</strong> — \"and by faith even Sarah, who was past the age, received the ability to conceive because she considered him who had made the promise to be faithful\" (<em>autē Sarra steira</em>: Sarah herself being barren — the very one who laughed at the promise [Gen 18:12] received what she doubted through faith): <em>dynamin eis katabolēn spermatos</em>: power/capacity for the laying-down of seed — <em>katabolē</em>: a throwing-down, founding; here the biological process of conception. <em>Para kairon hēlikias</em>: beyond the season of age, past the natural time — the impossibility is noted to anchor the miracle in biological fact. <em>Epei piston hēgēsato</em>: because she considered faithful — the faith-act is cognitive: an assessment of God's reliability.</p>",
    "12": "<p><strong>dio kai aph' henos egennēthēsan, kai tauta nenenekrōmenou, kathōs ta astra tou ouranou tō plēthei kai hōs hē ammos hē para to cheilos tēs thalassēs hē anarithmētos</strong> — \"and so from this one man, and he as good as dead, came descendants as numerous as the stars in the sky and as countless as the sand on the seashore\" (<em>nenenekrōmenou</em>: as good as dead — perfect passive participle of <em>nekroō</em>: having been made dead, rendered as dead; Abraham's reproductive capacity is described in the same terms as Isaac's future death-and-return [v19]): the double simile (stars of heaven + sand of the sea) draws on the covenant promises of Gen 15:5 and 22:17 — the very promises made to the one who was as good as dead. From biological death to astronomical and oceanic multitude: the contrast establishes the resurrection-logic of the covenant.</p>",
    "14": "<p><strong>hoi gar toiauta legontes emphanizousin hoti patrida epizētousin</strong> — \"people who say such things show that they are looking for a country of their own\" (<em>emphanizousin</em>: they make manifest, they publicly show — <em>emphanizō</em>: to reveal, to disclose; the profession of stranger-and-sojourner status reveals the inner orientation): the public confession of being a stranger (<em>xenos kai parepidēmos</em>) is a declaration of loyalty: one does not confess homelessness unless one is looking for a home elsewhere. The self-designation as strangers to the present order is simultaneously a declaration of citizenship in the coming order.</p>",
    "15": "<p><strong>kai ei men ekeinēs emnēmoneuon aph' hēs exēlthon, eichon an kairon anakampsai</strong> — \"if they had been thinking of the country they had left, they would have had opportunity to return\" (<em>eichon an kairon anakampsai</em>: they would have had an opportunity to return — second-class contrary-to-fact conditional): the argument from opportunity: those who left Mesopotamia were not prevented from returning; the roads were open, the option existed. The fact that they did not return shows the homeland they sought was not the one they left. <em>Anakampsai</em>: to return, to bend back — the image of turning one's path back to the point of origin.</p>",
    "16": "<p><strong>nyn de kreittōnos oregnontai, tout' estin epouraniou; dio ouk epaischydnetai autōn ho theos theos epikaleisthai, hētoimasen gar autois polin</strong> — \"instead, they were longing for a better country — a heavenly one. Therefore God is not ashamed to be called their God, for he has prepared a city for them\" (<em>oregnontai</em>: they long for, they stretch out for — <em>oregomai</em>: to reach out for, to desire with outstretched hand): <em>ouk epaischydnetai ho theos theos epikaleisthai autōn</em>: God is not ashamed to be called their God — the reversal of shame: the patriarchs bore the shame of homelessness; God bears the name of their God publicly and without shame. <em>Hētoimasen polin</em>: he has prepared a city — perfect: already done. The preparation preceded the heirs.</p>",
    "17": "<p><strong>Pistei prosenenoken Abraam ton Isaak peirazomenos, kai ton monogenē prosepheren ho tas epangelias anadexamenos</strong> — \"by faith Abraham, when God tested him, offered Isaac as a sacrifice. He who had received the promises was about to sacrifice his one and only son\" (<em>prosenenoken... prosepheren</em>: offered... was offering — the two verb forms are significant: <em>prosenenoken</em> is perfect [has offered — the faith-act is completed in God's sight before the knife falls]; <em>prosepheren</em> is imperfect [was offering — the process was underway]): <em>ton monogenē</em>: the only-begotten/unique son — the same word as 11:17 and John 3:16 for Christ; the typological resonance between Isaac and Christ is built into the vocabulary. <em>Ton tas epangelias anadexamenos</em>: the one who had received the promises — the person who received the promise is the same one who offers the promise-bearer.</p>",
    "18": "<p><strong>pros hon elalēthē hoti En Isaak klēthēsetai soi sperma</strong> — \"even though God had said to him, It is through Isaac that your offspring will be reckoned\" (Gen 21:12): the conflict is explicit: God promised seed through Isaac, then commanded the offering of Isaac. <em>En Isaak klēthēsetai soi sperma</em>: in/through Isaac will be called to you seed — the prepositional <em>en</em> (in/through) indicates that Isaac is the channel of the promised lineage, not merely one of many options. The command to sacrifice Isaac is thus a direct apparent contradiction of the promise-mechanism. The faith of v17 consists precisely in proceeding despite this apparent contradiction.</p>",
    "19": "<p><strong>logizomenos hoti kai ek nekrōn egeirein dynatos ho theos, hothen auton kai en parabolē ekomisato</strong> — \"Abraham reasoned that God could even raise the dead, and so in a manner of speaking he did receive Isaac back from death\" (<em>logizomenos</em>: reckoning, calculating, reasoning — the deliberate mental act of theological deduction): Abraham's faith is not blind but reasoned: if God can keep his promise only through Isaac, and God commands Isaac's death, then God must be able to raise the dead to fulfill the promise. <em>En parabolē</em>: in a parable, in a type — the recovery of Isaac is the type; the resurrection of Christ is the antitype. Isaac's survival of the intended death is a parabolic prefiguring of the resurrection.</p>",
    "20": "<p><strong>Pistei kai peri mellontōn eulogēsen Isaak ton Iakōb kai ton Ēsau</strong> — \"by faith Isaac blessed Jacob and Esau in regard to their future\" (<em>peri mellontōn</em>: concerning things about to come, future things): Isaac's blessing of his sons was an act of faith because the blessings concerned things entirely beyond Isaac's power to guarantee. <em>Eulogēsen</em>: blessed — the patriarchal blessing was not mere wish but a faith-speech that committed God to the future of the blessed. The fact that the blessing held even when it was obtained through deception (Gen 27) is evidence of divine sovereignty over the means by which the promise advances.</p>",
    "21": "<p><strong>Pistei Iakōb apothnēskōn hekaston tōn huiōn Iōsēph eulogēsen, kai prosekunēsen epi to akron tēs rhabdou autou</strong> — \"by faith Jacob, when he was dying, blessed each of Joseph's sons, and worshipped as he leaned on the top of his staff\" (Gen 48:15-16; 47:31): <em>apothnēskōn</em>: dying — the present participle; blessing on the threshold of death is the faith-act. The detail of leaning on the staff (from Gen 47:31 LXX, where the MT has \"head of the bed\") is a translation difference; the LXX had <em>rhabdon</em> where the MT had <em>mittah</em>: the unpointed Hebrew allowed two readings. The posture of worship while dying is the faith-expression Hebrews highlights.</p>",
    "22": "<p><strong>Pistei Iōsēph teleutōn peri tēs exodou tōn huiōn Israēl emnēmoneusen kai peri tōn ostōn autou eneteilato</strong> — \"by faith Joseph, when he was dying, spoke of the exodus of the Israelites and gave instructions about his bones\" (Gen 50:24-25): <em>tēs exodou</em>: the exodus — the same word Luke uses for Jesus's departure in the Transfiguration (Luke 9:31). Joseph's faith-act is prophetic: dying in Egypt, he spoke of a future departure from Egypt and committed his bones to go with the departing people. <em>Peri tōn ostōn autou eneteilato</em>: gave instructions about his bones — Gen 50:25, the oath Moses honored in Exod 13:19. The bones left Egypt as a sign that Joseph's faith reached beyond his own death to the promised inheritance.</p>",
    "23": "<p><strong>Pistei Mōysēs gennētheis ekrybē trimēnon hypo tōn paterōn autou, dioti eidon asteion to paidion kai ouk ephobēthēsan to diatagma tou basileōs</strong> — \"by faith Moses' parents hid him for three months after he was born, because they saw he was a fine child, and they were not afraid of the king's edict\" (<em>asteion to paidion</em>: the child was fine/beautiful — <em>asteios</em>: graceful, well-formed; Acts 7:20 uses <em>asteios tō theō</em>, beautiful to God): the faith-act is the parents', not Moses's — they saw something in the child and acted on it in defiance of royal decree. <em>Ouk ephobēthēsan to diatagma tou basileōs</em>: they were not afraid of the king's edict — the same structure as Moses's non-fear of the king's anger in v27.</p>",
    "25": "<p><strong>mallon helomenos synkakouchesthai tō laō tou theou ē proskairon echein hamartias apolausin</strong> — \"he chose to be mistreated along with the people of God rather than to enjoy the fleeting pleasures of sin\" (<em>helomenos</em>: having chosen — aorist middle participle of <em>haireō</em>: to take for oneself, to choose deliberately; the middle voice emphasizes the personal, self-involving character of the choice): <em>proskairon</em>: temporary, for a season — <em>pros kairon</em>: towards/for a time; the pleasures of sin are characterized by their temporality. <em>Apolausin</em>: enjoyment, pleasure — the Epicurean vocabulary of present pleasure; Moses's calculation reverses it: temporary pleasure vs. lasting reward.</p>",
    "27": "<p><strong>Pistei katelipen Aigupton mē phobētheis ton thymon tou basileōs, ton gar aoroton hōs horōn ekarteresen</strong> — \"by faith he left Egypt, not fearing the king's anger; he persevered because he saw him who is invisible\" (<em>ton aoroton hōs horōn</em>: the invisible one as seeing — the paradox of faith-sight: seeing what cannot be seen physically): <em>aoroton</em>: the unseen, invisible one — the divine invisibility is not absence but the nature of God's being. <em>Ekarteresen</em>: endured, persevered — <em>kartereō</em>: to be strong, to hold one's ground (from <em>kratos</em> = strength); the endurance is strength-based, not mere resignation. Moses held his position because his sight was fixed on the one who cannot be seen by the eyes.</p>",
    "28": "<p><strong>Pistei pepoiēken to pascha kai tēn proschusin tou haimatos, hina mē ho olothreuōn ta prōtotoka thigē autōn</strong> — \"by faith he kept the Passover and the application of blood, so that the destroyer of the firstborn would not touch them\" (<em>pepoiēken</em>: has kept/made — perfect active: the faith-act stands permanently): <em>proschusin tou haimatos</em>: the pouring/sprinkling on of blood — <em>prochysis</em>: a pouring forth; the application of the Passover blood to the doorposts. <em>Ho olothreuōn</em>: the destroyer — the destroying angel of Exod 12:23; <em>thigē</em>: might touch — the aorst subjunctive of <em>thinganō</em>: to touch, to make contact. The blood-application is the faith-act that created the boundary the destroyer could not cross.</p>",
    "29": "<p><strong>Pistei diebēsan tēn Erythrān Thalassan hōs dia xēras gēs, hēs perian labontes hoi Aigyptioi katepothēsan</strong> — \"by faith the people passed through the Red Sea as on dry land; but when the Egyptians tried to do so, they were drowned\" (<em>diebēsan</em>: passed through — aorist of <em>diabainō</em>: to cross over, to traverse): the same water that was dry land for Israel was drowning water for Egypt — the same reality, differentiated by faith. <em>Hōs dia xēras gēs</em> (as through dry land): the <em>hōs</em> (as, like) — as if it were dry land, though it was sea-bottom. <em>Katepothēsan</em>: were swallowed up — <em>katapinō</em>: to drink down, to swallow completely; the passive: the sea swallowed the Egyptians who pursued on the same basis.</p>",
    "30": "<p><strong>Pistei ta teichē Ierichō epeson kyklōthenta epi hepta hēmeras</strong> — \"by faith the walls of Jericho fell, after the army had marched around them for seven days\" (<em>epeson</em>: fell — aorist; <em>kyklōthenta</em>: having been circled — aorist passive participle of <em>kykloō</em>: to encircle): the faith-logic: seven days of marching around walls achieves nothing militarily — the walls fell not by siege-craft but by obedience to a divine command whose rationality was not self-evident. The connection between the commanded action and the result was faith alone.</p>",
    "31": "<p><strong>Pistei Raab hē pornē ou synap ōleto tois apeitēsasin, dexamēnē tous kataskopous met' eirēnēs</strong> — \"by faith Rahab the prostitute did not perish with those who were disobedient, because she welcomed the spies in peace\" (<em>hē pornē</em>: the prostitute — the social status is retained to heighten the faith-contrast: the Canaanite prostitute believed what Israel had heard of YHWH and acted on it): <em>tois apeitēsasin</em>: those who were disobedient — the same <em>apeithia</em>-root as the wilderness generation; the Jericho population's failure is categorized as disobedience, implying they had sufficient information to act differently. <em>Met' eirēnēs</em>: in peace — her welcome was not coerced but peaceful, establishing covenant-like solidarity.</p>",
    "32": "<p><strong>kai ti eti legō; epileipsei gar me diēgoumenon ho chronos peri Gedeon, Barak, Sampson, Iephthae, Dauid te kai Samouēl kai tōn prophētōn</strong> — \"and what more shall I say? Time would fail me to tell of Gideon, Barak, Samson, Jephthah, David, Samuel, and the prophets\" (<em>epileipsei gar me diēgoumenon ho chronos</em>: time will fail me as I narrate — the rhetorical device of <em>paralipsis</em> / <em>praeteritio</em>: listing what one says cannot be listed): the list order is not strictly chronological (Barak precedes Samson, but David follows Jephthah); the rhetorical move is cumulative impression, not historical sequence. <em>Diēgoumenon</em>: narrating — the author is aware of his own discourse, breaking the narrative frame to speak about the act of narrating.</p>",
    "34": "<p><strong>esbesan dynamin pyros, ephygon stomata machairēs, enedunamōthēsan apo astheneias, egenethesan ischyroi en polemō, parembolas eklinan allotriōn</strong> — \"who quenched the fury of the flames, and escaped the edge of the sword; whose weakness was turned to strength; and who became powerful in battle and routed foreign armies\" (<em>esbesan dynamin pyros</em>: quenched the power of fire — the three Hebrew youths in the furnace [Dan 3]; <em>dynamin pyros</em>: the power of fire, not merely the fire itself): <em>enedunamōthēsan apo astheneias</em>: were strengthened out of weakness — <em>apo</em>: the weakness was the starting point from which the strengthening emerged. <em>Parembolas eklinan allotriōn</em>: they caused the camps of foreigners to turn, to flee — <em>eklinō</em>: to bend, to turn from.</p>",
    "36": "<p><strong>heteroi de empaigmōn kai mastigōn perian labontes, eti de desmaōn kai phylakēs</strong> — \"some faced jeers and flogging, and even chains and imprisonment\" (<em>empaigmōn</em>: of mockings, derisions — from <em>empaizō</em>: to mock, to play-act at someone's expense; the same word for the mocking of Jesus in the passion narratives): the two tiers of suffering are noted: those who received miraculous deliverance (vv32-35) and those who suffered without physical rescue (vv36-38). Both categories are commended equally by faith. The structure prevents a prosperity-faith reading: faith does not guarantee miraculous rescue.</p>",
    "37": "<p><strong>elethasthēsan, epristvthēsan, en phonō machairēs apethanon, periēlthon en mēlōtais, en aigeiais dermasin, hysteroumenoi, thlibomenoi, kakouchoumenoi</strong> — \"they were put to death by stoning; they were sawn in two; they were killed by the sword. They went about in sheepskins and goatskins, destitute, persecuted and mistreated\" (<em>epristvthēsan</em>: they were sawn in two — traditionally applied to Isaiah [not in the OT text, but in Jewish tradition recorded in Lives of the Prophets]): <em>en mēlōtais, en aigeiais dermasin</em>: in sheepskins, in goat-skins — the covering of prophets, Elijah's mantle (1 Kgs 19:13); the clothing marks them as outsiders to civilization. <em>Hysteroumenoi, thlibomenoi, kakouchoumenoi</em>: lacking, pressed, maltreated — three progressive participles of suffering.</p>",
    "38": "<p><strong>hōn ouk ēn axios ho kosmos, epi erēmiais planōmenoi kai oresin kai spēlaiois kai tais opais tēs gēs</strong> — \"the world was not worthy of them. They wandered in deserts and mountains, and in caves and holes in the ground\" (<em>hōn ouk ēn axios ho kosmos</em>: of whom the world was not worthy): the evaluative reversal: from the world's perspective they were marginal figures, driven out and hiding; from God's perspective they were too good for the world that rejected them. <em>Epi erēmiais planōmenoi</em>: wandering in desolate places — the irony is that those who sought the heavenly city were reduced to inhabiting caves and holes; the dispossession confirms the reality of their citizenship elsewhere.</p>",
    "40": "<p><strong>tou theou peri hēmōn kreition ti problepsamenos, hina mē chōris hēmōn teleiōthōsin</strong> — \"God had planned something better for us so that only together with us would they be made perfect\" (<em>problepsamenos</em>: having foreseen and provided for beforehand — <em>pro</em>: before + <em>blepō</em>: to see; the divine foreseeing that shapes the historical arrangement): <em>kreition ti</em>: something better — the better thing is the completed Christ-event that the OT saints anticipated but did not receive. <em>Hina mē chōris hēmōn teleiōthōsin</em>: so that apart from us they would not be made perfect — the perfection is corporate: the new covenant community is the completion-context for OT faith. The cloud of witnesses cannot receive their perfection without the community for whom Christ has come.</p>"
  }
}
""")

def main():
    existing = load_comm("mkt-original", "hebrews")
    merge_comm(existing, HEBREWS)
    save_comm("mkt-original", "hebrews", existing)
    total = sum(len(v) for v in existing.values())
    print(f"Hebrews 10-11 mkt-original gaps filled: {len(existing)} chapters, {total} verses written.")

if __name__ == "__main__":
    main()
